 23→public class HoodSubsystem extends SubsystemBase {
 24→
 25→  private final ShooterCalculator calculator;
 26→
 27→  private final SparkMax hoodMax;
 28→  private final SmartMotorControllerConfig smartHoodMotorConfig;
 29→  private final SmartMotorController hoodMotor;
 30→  private final ArmConfig hoodMechanismConfig;
 31→  private final Arm hood;
 32→
 33→  private final HoodInputsAutoLogged inputs;
 34→
 35→  private static HoodSubsystem instance;
 36→
 37→  private double angleCalibration;
 38→
 39→  private HoodSubsystem() {
 40→    calculator = ShooterCalculator.getInstance();
 41→    smartHoodMotorConfig =
 42→        new SmartMotorControllerConfig(this)
 43→            .withIdleMode(MotorMode.BRAKE)
 44→            .withGearing(HoodConstants.MOTOR_GEARING)
 45→            .withMotorInverted(false)
 46→            .withSoftLimit(
 47→                HoodConstants.Position.HOOD_MIN_ANGLE, HoodConstants.Position.HOOD_MAX_ANGLE)
 48→            .withStatorCurrentLimit(Amps.of(20))
 49→            .withClosedLoopRampRate(Milliseconds.of(100))
 50→            .withClosedLoopController(
 51→                HoodConstants.ClosedLoopController.kP,
 52→                HoodConstants.ClosedLoopController.kI,
 53→                HoodConstants.ClosedLoopController.kD)
 54→            .withSimClosedLoopController(
 55→                HoodConstants.ClosedLoopController.kP,
 56→                HoodConstants.ClosedLoopController.kI,
 57→                HoodConstants.ClosedLoopController.kD)
 58→            .withFeedforward(new SimpleMotorFeedforward(0.135, 4, 0))
 59→            .withSimFeedforward(new SimpleMotorFeedforward(0.135, 4, 0))
 60→            .withControlMode(ControlMode.CLOSED_LOOP);
 61→
 62→    hoodMax = new SparkMax(8, MotorType.kBrushless);
 63→
 64→    hoodMotor = new SparkWrapper(hoodMax, HoodConstants.HOOD_MOTOR, smartHoodMotorConfig);
 65→
 66→    hoodMechanismConfig =
 67→        new ArmConfig(hoodMotor)
 68→            .withStartingPosition(Degrees.of(75))
 69→            .withHardLimit(
 70→                HoodConstants.Position.HOOD_MIN_ANGLE, HoodConstants.Position.HOOD_MAX_ANGLE)
 71→            .withLength(HoodConstants.HOOD_SIZE)
 72→            .withMass(HoodConstants.HOOD_MASS);
 73→
 74→    hood = new Arm(hoodMechanismConfig);
 75→
 76→    inputs = new HoodInputsAutoLogged();
 77→
 78→    SmartDashboard.putNumber("Calibration/Hood", 41);
 79→    angleCalibration = 41;
 80→  }
 81→
 82→  public static HoodSubsystem getInstance() {
 83→    if (instance == null) {
 84→      instance = new HoodSubsystem();
 85→    }
 86→    return instance;
 87→  }
 88→
 89→  @Override
 90→  public void periodic() {
 91→    hood.updateTelemetry();
 92→    updateInputs();
 93→    this.angleCalibration = SmartDashboard.getNumber("Calibration/Hood", 41);
 94→  }
 95→
 96→  @Override
 97→  public void simulationPeriodic() {
 98→    hood.simIterate();
 99→  }
100→
101→  private void updateInputs() {
102→    inputs.currentAngle = hood.getAngle().in(Degrees);
103→    inputs.targetAngle = calculator.getParameters().hoodAngle();
104→    inputs.atTarget = isAtTargetAngle();
105→    inputs.angleError =
106→        Math.abs(hood.getAngle().in(Degrees) - calculator.getParameters().hoodAngle());
107→
108→    Logger.processInputs("Subsystems/Shooter/Hood/", inputs);
109→  }
110→
111→  public Command trackHub() {
112→    return hood.setAngle(() -> Degrees.of(calculator.getParameters(true).hoodAngle()));
113→  }
114→
115→  public Command trackPass() {
116→    return hood.setAngle(() -> Degrees.of(calculator.getParameters(false).hoodAngle()));
117→  }
118→
119→  public Command trackNonOdometry() {
120→    return hood.setAngle(() -> Degrees.of(73));
121→  }
122→
123→  public boolean isAtTargetAngle() {
124→    return hood.getAngle()
125→        .isNear(
126→            this.hood.getMechanismSetpoint().orElse(Degrees.of(75)),
127→            HoodConstants.Position.ANGLE_ERROR_ALLOWED);
128→  }
129→
130→  public double getMinAngleDegrees() {
131→    return HoodConstants.Position.HOOD_MIN_ANGLE.in(Degrees);
132→  }
133→
134→  public double getMaxAngleDegrees() {
135→    return HoodConstants.Position.HOOD_MAX_ANGLE.in(Degrees);
136→  }
137→
138→  public Command goToTargetAngleCalibration() {
139→    return hood.setAngle(() -> Degrees.of(angleCalibration));
140→  }
141→}
