 26→public class FlyWheelSubsystem extends SubsystemBase {
 27→
 28→  private final ShooterCalculator calculator;
 29→
 30→  private final SmartMotorControllerConfig motorConfig;
 31→  private final TalonFX leadMotor;
 32→  private final SmartMotorController smartFlywheelMotor;
 33→  private final FlyWheelConfig flyWheelConfig;
 34→  private final FlyWheel flywheelMechanism;
 35→
 36→  private final FlyWheelInputsAutoLogged inputs;
 37→
 38→  private static FlyWheelSubsystem instance;
 39→
 40→  private VelocityTorqueCurrentFOC torqueCurrentRequest = new VelocityTorqueCurrentFOC(RPM.of(0));
 41→
 42→  private double flyWheelRPM;
 43→
 44→  private AngularVelocity setpoint = RPM.of(0);
 45→
 46→  private FlyWheelSubsystem() {
 47→    this.calculator = ShooterCalculator.getInstance();
 48→
 49→    this.motorConfig =
 50→        new SmartMotorControllerConfig(this)
 51→            .withMotorInverted(true)
 52→            .withFollowers(Pair.of(new TalonFX(18, CANBus.roboRIO()), true))
 53→            .withIdleMode(MotorMode.BRAKE)
 54→            .withGearing(FlyWheelsConstants.MOTOR_GEARING)
 55→            .withSupplyCurrentLimit(Amps.of(30))
 56→            .withStatorCurrentLimit(Amps.of(120))
 57→            .withClosedLoopController(
 58→                FlyWheelsConstants.ClosedLoopController.kP,
 59→                FlyWheelsConstants.ClosedLoopController.kI,
 60→                FlyWheelsConstants.ClosedLoopController.kD)
 61→            .withSimClosedLoopController(4, 0, 0)
 62→            .withFeedforward(new SimpleMotorFeedforward(0, 0, 0))
 63→            .withSimFeedforward(new SimpleMotorFeedforward(0.19, 0.11, 0))
 64→            .withControlMode(ControlMode.CLOSED_LOOP);
 65→
 66→    this.torqueCurrentRequest.withFeedForward(FlyWheelsConstants.FEEDFORWARD_TORQUE_CURRENT_A);
 67→
 68→    this.leadMotor = new TalonFX(19);
 69→
 70→    this.smartFlywheelMotor =
 71→        new TalonFXWrapper(this.leadMotor, FlyWheelsConstants.FLYWHEEL_MOTOR, this.motorConfig);
 72→
 73→    this.flyWheelConfig =
 74→        new FlyWheelConfig(smartFlywheelMotor)
 75→            .withMOI(FlyWheelsConstants.FLYWHEEL_SIZE, FlyWheelsConstants.FLYWHEEL_MASS);
 76→
 77→    this.flywheelMechanism = new FlyWheel(flyWheelConfig);
 78→
 79→    this.inputs = new FlyWheelInputsAutoLogged();
 80→
 81→    SmartDashboard.putNumber("Calibration/FlyWheelRPM", 0);
 82→    this.flyWheelRPM = 0;
 83→  }
 84→
 85→  public static FlyWheelSubsystem getInstance() {
 86→    if (instance == null) {
 87→      instance = new FlyWheelSubsystem();
 88→    }
 89→    return instance;
 90→  }
 91→
 92→  @Override
 93→  public void periodic() {
 94→    this.flywheelMechanism.updateTelemetry();
 95→    this.updateInputs();
 96→    this.flyWheelRPM = SmartDashboard.getNumber("Calibration/FlyWheelRPM", 0);
 97→  }
 98→
 99→  @Override
100→  public void simulationPeriodic() {
101→    this.flywheelMechanism.simIterate();
102→  }
103→
104→  private void updateInputs() {
105→    this.inputs.currentVelocity = this.smartFlywheelMotor.getRotorVelocity().in(RPM);
106→    this.setpoint = torqueCurrentRequest.getVelocityMeasure();
107→    this.inputs.targetVelocity = setpoint.in(RPM);
108→    this.inputs.atTarget = isAtTargetVelocity();
109→    Logger.processInputs("Subsystems/Shooter/FlyWheels/", inputs);
110→  }
111→
112→  public Command runLowVelocity() {
113→    return this.runFlywheel(() -> RPM.of(1000));
114→  }
115→
116→  public Command stoppedVelocity() {
117→    return this.runFlywheel(() -> RPM.of(0));
118→  }
119→
120→  public Command shootHub() {
121→    return this.runFlywheel(
122→        () -> RPM.of(ShooterCalculator.getInstance().getParameters(true).flywheelSpeed()));
123→  }
124→
125→  public Command shootPass() {
126→    return this.runFlywheel(
127→        () -> RPM.of(ShooterCalculator.getInstance().getParameters(false).flywheelSpeed()));
128→  }
129→
130→  public Command shootNonOdometry() {
131→    return this.runFlywheel(() -> RPM.of(2700.0));
132→  }
133→
134→  private Command runFlywheel(Supplier<AngularVelocity> velocity) {
135→    return this.run(() -> leadMotor.setControl(torqueCurrentRequest.withVelocity(velocity.get())));
136→  }
137→
138→  public Command runVelocityTorqueControlCalibration() {
139→    return this.run(
140→        () -> leadMotor.setControl(torqueCurrentRequest.withVelocity(this.flyWheelRPM / 60)));
141→  }
142→
143→  public boolean isAtTargetVelocity() {
144→    return this.flywheelMechanism
145→        .getSpeed()
146→        .isNear(setpoint, FlyWheelsConstants.Velocity.VELOCITY_ERROR_ALLOWED);
147→  }
148→}
