 14→import frc.robot.RobotStates;
 15→import frc.robot.constants.FieldConstants;
 16→import frc.robot.constants.FieldConstants.FieldStructurePoses;
 17→import frc.robot.subsystems.shooter.interpolatingTreeMaps.FeedingMaps;
 18→import frc.robot.subsystems.shooter.interpolatingTreeMaps.InterpolatingTreeMaps;
 19→import frc.robot.subsystems.shooter.interpolatingTreeMaps.ShootingMaps;
 20→import frc.robot.subsystems.shooter.turret.TurretConstants;
 21→import org.littletonrobotics.junction.AutoLogOutput;
 22→import org.littletonrobotics.junction.Logger;
 23→
 24→public class ShooterCalculator {
 25→  private static ShooterCalculator instance;
 26→
 27→  private final LinearFilter turretAngleFilter =
 28→      LinearFilter.movingAverage((int) (0.1 / Constants.loopPeriodSecs));
 29→  private final LinearFilter hoodAngleFilter =
 30→      LinearFilter.movingAverage((int) (0.1 / Constants.loopPeriodSecs));
 31→
 32→  private Rotation2d lastTurretAngle;
 33→  private double lastHoodAngle;
 34→  private Rotation2d turretAngle;
 35→  private double hoodAngle = Double.NaN;
 36→  private double turretVelocity;
 37→  private double hoodVelocity;
 38→
 39→  public static ShooterCalculator getInstance() {
 40→    if (instance == null) instance = new ShooterCalculator();
 41→    return instance;
 42→  }
 43→
 44→  public record ShootingParameters(
 45→      boolean isValid,
 46→      Rotation2d turretAngle,
 47→      double turretVelocity,
 48→      double hoodAngle,
 49→      double hoodVelocity,
 50→      double flywheelSpeed) {}
 51→
 52→  // Cache parameters
 53→  private ShootingParameters latestParameters = null;
 54→
 55→  private boolean lastState;
 56→
 57→  private final Transform2d robotToTurret = TurretConstants.TURRET_OFFSET_FROM_ROBOT_CENTER;
 58→
 59→  private static double phaseDelay = TurretConstants.PHASE_DELAY;
 60→
 61→  @AutoLogOutput private double distanceToTarget = 0;
 62→
 63→  public ShootingParameters getParameters() {
 64→    return this.getParameters(true);
 65→  }
 66→
 67→  public ShootingParameters getLastParameters() {
 68→    return latestParameters;
 69→  }
 70→
 71→  public ShootingParameters getParameters(boolean shooting) {
 72→    if (latestParameters != null && lastState == shooting) {
 73→      return latestParameters;
 74→    }
 75→
 76→    lastState = shooting;
 77→
 78→    InterpolatingTreeMaps maps = getMaps(shooting);
 79→
 80→    // Calculate estimated pose while accounting for phase delay
 81→    Pose2d estimatedPose = RobotStates.getInstance().getRobotPose();
 82→    ChassisSpeeds robotRelativeVelocity = RobotStates.getInstance().getRobotVelocity();
 83→    estimatedPose =
 84→        estimatedPose.exp(
 85→            new Twist2d(
 86→                robotRelativeVelocity.vxMetersPerSecond * phaseDelay,
 87→                robotRelativeVelocity.vyMetersPerSecond * phaseDelay,
 88→                robotRelativeVelocity.omegaRadiansPerSecond * phaseDelay));
 89→    // Calculate distance from turret to target
 90→    Translation2d target = getTargetTranslation2d(shooting);
 91→    Logger.recordOutput("target", target);
 92→    Pose2d turretPosition = estimatedPose.transformBy(robotToTurret);
 93→    double turretToTargetDistance = target.getDistance(turretPosition.getTranslation());
 94→
 95→    // Calculate field relative turret velocity
 96→    ChassisSpeeds robotVelocity = RobotStates.getInstance().getFieldVelocity();
 97→    double robotAngle = estimatedPose.getRotation().getRadians();
 98→    double turretVelocityX =
 99→        robotVelocity.vxMetersPerSecond
100→            + robotVelocity.omegaRadiansPerSecond
101→                * (robotToTurret.getY() * Math.cos(robotAngle)
102→                    - robotToTurret.getX() * Math.sin(robotAngle));
103→    double turretVelocityY =
104→        robotVelocity.vyMetersPerSecond
105→            + robotVelocity.omegaRadiansPerSecond
106→                * (robotToTurret.getX() * Math.cos(robotAngle)
107→                    - robotToTurret.getY() * Math.sin(robotAngle));
108→
109→    // Account for imparted velocity by robot (turret) to offset
110→    double timeOfFlight;
111→    Pose2d lookaheadPose = turretPosition;
112→    double lookaheadTurretToTargetDistance = turretToTargetDistance;
113→    for (int i = 0; i < 20; i++) {
114→      timeOfFlight = maps.getTimeOfFlightMap().get(lookaheadTurretToTargetDistance);
115→      double offsetX = turretVelocityX * timeOfFlight;
116→      double offsetY = turretVelocityY * timeOfFlight;
117→      lookaheadPose =
118→          new Pose2d(
119→              turretPosition.getTranslation().plus(new Translation2d(offsetX, offsetY)),
120→              turretPosition.getRotation());
121→      lookaheadTurretToTargetDistance = target.getDistance(lookaheadPose.getTranslation());
122→      distanceToTarget = lookaheadTurretToTargetDistance;
123→    }
124→
125→    // Calculate parameters accounted for imparted velocity
126→    turretAngle = target.minus(lookaheadPose.getTranslation()).getAngle();
127→    hoodAngle = maps.getHoodAngleMap().get(lookaheadTurretToTargetDistance).getDegrees();
128→    if (lastTurretAngle == null) lastTurretAngle = turretAngle;
129→    if (Double.isNaN(lastHoodAngle)) lastHoodAngle = hoodAngle;
130→    turretVelocity =
131→        turretAngleFilter.calculate(
132→            turretAngle.minus(lastTurretAngle).getRadians() / Constants.loopPeriodSecs);
133→    hoodVelocity =
134→        hoodAngleFilter.calculate((hoodAngle - lastHoodAngle) / Constants.loopPeriodSecs);
135→    lastTurretAngle = turretAngle;
136→    lastHoodAngle = hoodAngle;
137→
138→    Logger.recordOutput("LookAheadPose", lookaheadPose);
139→
140→    latestParameters =
141→        new ShootingParameters(
142→            lookaheadTurretToTargetDistance >= maps.getMinDistance()
143→                && lookaheadTurretToTargetDistance <= maps.getMaxDistance(),
144→            turretAngle.minus(Rotation2d.fromRadians(robotAngle)),
145→            turretVelocity,
146→            hoodAngle,
147→            hoodVelocity,
148→            maps.getFlywheelSpeedMap().get(lookaheadTurretToTargetDistance));
149→
150→    return latestParameters;
151→  }
