169→            cameraFrontRight, VisionConstants.robotToCamArducamFrontRight);
170→
171→    PhotonCamera cameraFrontLeft = new PhotonCamera(VisionConstants.frontLeftArducamName);
172→    PoseEstimator photonFrontLeft =
173→        new PhotonVisionPoseEstimator(cameraFrontLeft, VisionConstants.robotToCamArducamFrontLeft);
174→
175→    Optional<PoseEstimation> photonFrontRightPoseEstimation =
176→        photonFrontRight.getEstimatedPose(this.getPose());
177→
178→    if (photonFrontRightPoseEstimation.isEmpty()) {
179→      resetTranslation(defaultPosition);
180→      this.positionUpdated = true;
181→    } else {
182→      resetTranslation(
183→          photonFrontRightPoseEstimation.get().estimatedPose.getTranslation().toTranslation2d());
184→      this.positionUpdated = true;
185→    }
186→
187→    Optional<PoseEstimation> photonFrontLeftPoseEstimation =
188→        photonFrontLeft.getEstimatedPose(this.getPose());
189→
190→    if (photonFrontLeftPoseEstimation.isEmpty()) {
191→      resetTranslation(defaultPosition);
192→      this.positionUpdated = true;
193→    } else {
194→      resetTranslation(
195→          photonFrontLeftPoseEstimation.get().estimatedPose.getTranslation().toTranslation2d());
196→      this.positionUpdated = true;
197→    }
