178→  public Command extending(Current threshhold) {
179→    Debouncer currentDebouncer =
180→        new Debouncer(0.3); // Current threshold is only detected if exceeded for 0.4 seconds.
181→    Voltage runVolts = Volts.of(-12); // Volts required to run the mechanism to the limit.
182→    Distance limitHit =
183→        ExtensorConstants.setpoints.INTAKE_EXTENDED_POSITION; // Limit which gets hit.
184→    AngularVelocity velocityThreshold =
185→        DegreesPerSecond.of(
186→            2); // The maximum amount of movement for the extensor to be considered "hitting the
187→    // hard limit".
188→    return Commands.startRun(
189→            extensorMotor::stopClosedLoopController, // Stop the closed loop controller
190→            () -> extensorMotor.setVoltage(runVolts)) // Set the voltage of the motor
191→        .until(
192→            () ->
193→                currentDebouncer.calculate(
194→                    extensorMotor.getStatorCurrent().gte(threshhold)
195→                        && extensorMotor.getMechanismVelocity().abs(DegreesPerSecond)
196→                            <= velocityThreshold.in(DegreesPerSecond)))
197→        .finallyDo(
198→            () -> {
199→              extensorMotor.setEncoderPosition(limitHit);
200→              extensorMotor.startClosedLoopController();
201→            });
202→  }
