150→  public void periodic() {
151→
152→    odometryLock.lock(); // Prevents odometry updates while reading data
153→    gyroIO.updateInputs(gyroInputs);
154→    Logger.processInputs("Drive/Gyro", gyroInputs);
155→    for (var module : modules) {
156→      module.periodic();
157→    }
158→    odometryLock.unlock();
159→
160→    // Stop moving when disabled
161→    if (DriverStation.isDisabled()) {
162→      for (var module : modules) {
163→        module.stop();
164→      }
165→    }
166→
167→    Logger.recordOutput("Odometry/Robot", getPose());
168→    Logger.recordOutput("SwerveStates/Measured", getModuleStates());
169→    // Log empty setpoint states when disabled
170→    if (DriverStation.isDisabled()) {
171→      Logger.recordOutput("SwerveStates/Setpoints", new SwerveModuleState[] {});
172→      Logger.recordOutput("SwerveStates/SetpointsOptimized", new SwerveModuleState[] {});
173→      Logger.recordOutput("SwerveChassisSpeeds/Measured", new ChassisSpeeds());
174→    } else {
175→      Logger.recordOutput("SwerveChassisSpeeds/Measured", getChassisSpeeds());
176→    }
177→
178→    // Update odometry
179→    double[] sampleTimestamps =
180→        modules[0].getOdometryTimestamps(); // All signals are sampled together
181→    int sampleCount = sampleTimestamps.length;
182→    for (int i = 0; i < sampleCount; i++) {
183→      // Read wheel positions and deltas from each module
184→      SwerveModulePosition[] modulePositions = new SwerveModulePosition[4];
185→      SwerveModulePosition[] moduleDeltas = new SwerveModulePosition[4];
186→      for (int moduleIndex = 0; moduleIndex < 4; moduleIndex++) {
187→        modulePositions[moduleIndex] = modules[moduleIndex].getOdometryPositions()[i];
188→        moduleDeltas[moduleIndex] =
189→            new SwerveModulePosition(
190→                modulePositions[moduleIndex].distanceMeters
191→                    - lastModulePositions[moduleIndex].distanceMeters,
192→                modulePositions[moduleIndex].angle);
193→        lastModulePositions[moduleIndex] = modulePositions[moduleIndex];
194→      }
195→
196→      // Update gyro angle
197→      if (gyroInputs.connected) {
198→        // Use the real gyro angle
199→        rawGyroRotation = gyroInputs.odometryYawPositions[i];
200→      } else {
201→        // Use the angle delta from the kinematics and module deltas
202→        Twist2d twist = kinematics.toTwist2d(moduleDeltas);
203→        rawGyroRotation = rawGyroRotation.plus(new Rotation2d(twist.dtheta));
204→      }
205→
206→      // Apply update
207→      poseEstimator.updateWithTime(sampleTimestamps[i], rawGyroRotation, modulePositions);
208→    }
209→
210→    RobotStates.getInstance().setRobotPose(getPose());
211→    RobotStates.getInstance().setRobotVelocity(getChassisSpeeds());
212→
213→    // Update gyro alert
214→    gyroDisconnectedAlert.set(!gyroInputs.connected && Constants.getMode() != Mode.SIM);
215→  }
