228→    // Log unoptimized setpoints and setpoint speeds
229→    Logger.recordOutput("SwerveStates/Setpoints", setpointStates);
230→    Logger.recordOutput("SwerveChassisSpeeds/Setpoints", discreteSpeeds);
231→
232→    // Send setpoints to modules
233→    for (int i = 0; i < 4; i++) {
234→      modules[i].runSetpoint(setpointStates[i]);
235→    }
236→
237→    // Log optimized setpoints (runSetpoint mutates each state)
238→    Logger.recordOutput("SwerveStates/SetpointsOptimized", setpointStates);
239→  }
