53→    inputs.yawVelocityRadPerSec = Units.degreesToRadians(yawVelocity.getValueAsDouble());
54→
55→    inputs.odometryYawTimestamps =
56→        yawTimestampQueue.stream().mapToDouble((Double value) -> value).toArray();
