58→        yawPositionQueue.stream()
59→            .map((Double value) -> Rotation2d.fromDegrees(value))
60→            .toArray(Rotation2d[]::new);
61→    yawTimestampQueue.clear();
62→    yawPositionQueue.clear();
63→  }
