196→        BaseStatusSignal.refreshAll(drivePosition, driveVelocity, driveAppliedVolts, driveCurrent);
197→    var turnStatus =
198→        BaseStatusSignal.refreshAll(turnPosition, turnVelocity, turnAppliedVolts, turnCurrent);
199→    var turnEncoderStatus = BaseStatusSignal.refreshAll(turnAbsolutePosition);

200→
201→    // Update drive inputs
202→    inputs.driveConnected = driveConnectedDebounce.calculate(driveStatus.isOK());
203→    inputs.drivePositionRad = Units.rotationsToRadians(drivePosition.getValueAsDouble());
204→    inputs.driveVelocityRadPerSec = Units.rotationsToRadians(driveVelocity.getValueAsDouble());
205→    inputs.driveAppliedVolts = driveAppliedVolts.getValueAsDouble();
206→    inputs.driveCurrentAmps = driveCurrent.getValueAsDouble();
207→
208→    // Update turn inputs
209→    inputs.turnConnected = turnConnectedDebounce.calculate(turnStatus.isOK());
210→    inputs.turnEncoderConnected = turnEncoderConnectedDebounce.calculate(turnEncoderStatus.isOK());
211→    inputs.turnAbsolutePosition = Rotation2d.fromRotations(turnAbsolutePosition.getValueAsDouble());
212→    inputs.turnPosition = Rotation2d.fromRotations(turnPosition.getValueAsDouble());
213→    inputs.turnPositionRadians = Units.rotationsToRadians(turnPosition.getValueAsDouble());
214→    inputs.turnVelocityRadPerSec = Units.rotationsToRadians(turnVelocity.getValueAsDouble());
215→    inputs.turnAppliedVolts = turnAppliedVolts.getValueAsDouble();
216→    inputs.turnCurrentAmps = turnCurrent.getValueAsDouble();
217→
218→    // Update odometry inputs
219→    inputs.odometryTimestamps =
220→        timestampQueue.stream().mapToDouble((Double value) -> value).toArray();
221→    inputs.odometryDrivePositionsRad =
222→        drivePositionQueue.stream()
223→            .mapToDouble((Double value) -> Units.rotationsToRadians(value))
224→            .toArray();
225→    inputs.odometryTurnPositions =
226→        turnPositionQueue.stream()
227→            .map((Double value) -> Rotation2d.fromRotations(value))
228→            .toArray(Rotation2d[]::new);
229→    timestampQueue.clear();
230→    drivePositionQueue.clear();
231→    turnPositionQueue.clear();
232→  }
