182→        () -> {
183→          Logger.recordOutput("EncodersCRT/encoder1", this.encoder1.getPosition());
184→          Logger.recordOutput("EncodersCRT/encoder2", this.encoder2.getPosition());
185→          Logger.recordOutput(
186→              "EncodersCRT/absoluteResult",
187→              determineTurretAngleDegrees(
188→                  Units.rotationsToDegrees(this.encoder1.getPosition()),
189→                  Units.rotationsToDegrees(this.encoder2.getPosition())));
190→        });
