192→
193→  private double getClosestTargetAngle(double targetAngle, double currentAngle) {
194→    double delta = (targetAngle - currentAngle) % 360;
195→
196→    if (delta > 180) {
197→      delta -= 360;
198→    } else if (delta < -180) {
199→      delta += 360;
200→    }
201→
202→    double potentialTarget = currentAngle + delta;
203→
204→    if (potentialTarget > TurretConstants.TURRET_MAX_ANGLE.in(Degrees)) {
205→      potentialTarget -= 360;
206→    } else if (potentialTarget < TurretConstants.TURRET_MIN_ANGLE.in(Degrees)) {
207→      potentialTarget += 360;
208→    }
209→
210→    return potentialTarget;
211→  }
212→
213→  private double determineTurretAngleDegrees(double e1, double e2) {
214→    double difference = e2 - e1;
215→    if (difference > 250) {
216→      difference -= 360;
217→    }
218→    if (difference < -250) {
219→      difference += 360;
220→    }
221→    difference *= TurretConstants.SLOPE;
222→
223→    double e1Rotations =
224→        (difference * TurretConstants.GEAR_0_TOOTH_COUNT / TurretConstants.GEAR_1_TOOTH_COUNT)
225→            / 360.0;
226→    double e1RotationsFloored = Math.floor(e1Rotations);
227→    double turretAngle =
228→        (e1RotationsFloored * 360.0 + e1)
229→            * (TurretConstants.GEAR_1_TOOTH_COUNT / TurretConstants.GEAR_0_TOOTH_COUNT);
230→    if (turretAngle - difference < -100) {
231→      turretAngle +=
232→          TurretConstants.GEAR_1_TOOTH_COUNT / TurretConstants.GEAR_0_TOOTH_COUNT * 360.0;
233→    } else if (turretAngle - difference > 100) {
234→      turretAngle -=
235→          TurretConstants.GEAR_1_TOOTH_COUNT / TurretConstants.GEAR_0_TOOTH_COUNT * 360.0;
236→    }
237→    return -turretAngle + 180;
238→  }
239→}
