253→  /**
254→   * Drives the robot field-oriented while locking its heading to a target angle.
255→   *
256→   * <p>The translational components ({@code vx}, {@code vy}) come from the given {@link
257→   * ChassisSpeeds}. Rotation is controlled automatically using an angle controller to track the
258→   * desired heading. When on the Red alliance, the target heading is flipped by 180° to maintain
259→   * consistent field-relative behavior.
260→   *
261→   * @param speeds Desired field-relative translational speeds
262→   * @param targetHeading Target field heading to maintain
263→   * @param allianceBasedVelocities Whether the heading should account for alliance orientation
264→   */
265→  protected void driveFieldOrientedLockedAngle(
266→      ChassisSpeeds speeds, Rotation2d targetHeading, boolean allianceBasedVelocities) {
267→    Rotation2d targetRotation = targetHeading;
268→    this.lastDesiredJoystickAngleRadians = targetRotation.getRadians();
269→    this.targetHeadingDegrees = targetRotation.getDegrees();
270→    this.targetHeadingRadians = targetRotation.getRadians();
271→    double omega =
272→        angleController.calculate(getHeading().getRadians(), targetRotation.getRadians());
273→    ChassisSpeeds adjustedSpeeds =
274→        new ChassisSpeeds(speeds.vxMetersPerSecond, speeds.vyMetersPerSecond, omega);
275→    if (allianceBasedVelocities) {
276→      driveFieldOrientedAllianceBased(adjustedSpeeds);
277→    } else {
278→      driveFieldOriented(adjustedSpeeds);
279→    }
280→  }
